class Solution:
    def sortEvenOdd(self, nums):
        n = len(nums)
        even_vals = sorted(nums[i] for i in range(0, n, 2))
        odd_vals = sorted((nums[i] for i in range(1, n, 2)), reverse=True)
        out = []
        ei = 0
        oi = 0
        for i in range(n):
            if i % 2 == 0:
                out.append(even_vals[ei])
                ei += 1
            else:
                out.append(odd_vals[oi])
                oi += 1
        return out

