var sortEvenOdd = function(nums) {
    const evens = [];
    const odds = [];
    for (let i = 0; i < nums.length; i++) {
        if (i % 2 === 0) evens.push(nums[i]);
        else odds.push(nums[i]);
    }
    evens.sort((a, b) => a - b);
    odds.sort((a, b) => b - a);
    const res = new Array(nums.length);
    let ei = 0, oi = 0;
    for (let i = 0; i < nums.length; i++) {
        if (i % 2 === 0) res[i] = evens[ei++];
        else res[i] = odds[oi++];
    }
    return res;
};
